mapper.select:
SELECT p.*, w.name as warehouse_name, s.name as supplier_name FROM inventory_products p LEFT JOIN inventory_warehouses w ON p.warehouse_id = w.id LEFT JOIN inventory_suppliers s ON p.supplier_id = s.id
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.product_code LIKE CONCAT('%', #{keyword}, '%'))
AND p.category = #{category}
AND p.warehouse_id = #{warehouseId}
ORDER BY p.id DESC

mapper.update:
UPDATE inventory_products
name = #{name}, spec = #{spec}, category = #{category}, unit = #{unit}, price = #{price}, stock = #{stock}, min_stock = #{minStock}, warehouse_id = #{warehouseId}, supplier_id = #{supplierId}, remark = #{remark},
WHERE id = #{id}
